4:["$","$L12",null,{"record":{"id":"grm_flaxfield_shirt_0042","shortcode":"L01","name":"Flaxfield Overshirt","maker":"Atelier Mireille","origin":"Marvão, Portugal","plainComposition":"60% pure flax linen & 40% soft cotton","compositionClaims":[{"id":"comp_flax","label":"Flax linen content","value":"60% — EU flax, field-retted","evidence":"certificate","register":"verified","facet":"weld","chainAnchored":true,"loggedBy":"Mateo Silva","loggedAt":"2026-03-02","evidenceRef":"MasterOfLinen-2026-FR-118.pdf"},{"id":"comp_cotton","label":"Cotton content","value":"40% — organic, GOTS scope","evidence":"certificate","register":"verified","facet":"saffron","chainAnchored":true,"loggedBy":"Mateo Silva","loggedAt":"2026-03-02","evidenceRef":"GOTS-2026-0098.pdf"}],"ecoMetrics":[{"id":"eco_carbon","label":"Carbon footprint","value":6.2,"unit":"kg CO₂e","fill":0.38,"benchmarkNote":"vs ~16 kg CO₂e for a comparable cotton shirt","evidence":"audit","chainAnchored":true},{"id":"eco_water","label":"Water consumption","value":1100,"unit":"litres","fill":0.55,"benchmarkNote":"brand estimate; method not independently checked","evidence":"self_declared","chainAnchored":false}],"certificates":[{"id":"cert_gots","label":"GOTS — organic textile","value":"Scope cert 0098, valid to 2027-01","evidence":"certificate","register":"verified","chainAnchored":true,"loggedBy":"Marcus Malik","loggedAt":"2026-02-18","evidenceRef":"GOTS-2026-0098.pdf"},{"id":"cert_oekotex","label":"OEKO-TEX Standard 100","value":"Class II, no SVHC above limits","evidence":"certificate","register":"verified","chainAnchored":true,"loggedBy":"Marcus Malik","loggedAt":"2026-02-18","evidenceRef":"OEKOTEX-100-2026-RT-44.pdf"},{"id":"cert_masteroflinen","label":"Master of Linen — European flax","value":"Traceable to FR/BE fibre","evidence":"certificate","register":"verified","chainAnchored":true,"loggedBy":"Mateo Silva","loggedAt":"2026-03-02","evidenceRef":"MasterOfLinen-2026-FR-118.pdf"},{"id":"cert_espr","label":"EU ESPR digital record","value":"Reg (EU) 2024/1781 conformant","evidence":"audit","register":"verified","chainAnchored":true,"loggedBy":"Marcus Malik","loggedAt":"2026-03-10","evidenceRef":"ESPR-DPP-conformance.pdf"}],"timeline":[{"id":"tier4","tier":4,"title":"Fibre — flax fields","place":"Normandy, France","body":"Field-retted European flax, harvested August. Cooperative-grown on the Channel coast where damp summers suit the crop.","claim":{"id":"tl_tier4","label":"Fibre source","value":"Normandy cooperative, 2025 harvest","evidence":"certificate","register":"verified","facet":"weld","chainAnchored":true,"loggedBy":"Mateo Silva","loggedAt":"2026-03-02","evidenceRef":"MasterOfLinen-2026-FR-118.pdf"}},{"id":"tier3","tier":3,"title":"Yarn — spinning & dyeing","place":"Guimarães, Portugal","body":"Wet-spun for a fine hand, then dyed with weld and indigo woad in low-liquor baths.","claim":{"id":"tl_tier3","label":"Spinning & natural dye","value":"Weld + woad, low-liquor","evidence":"audit","register":"verified","facet":"woad","chainAnchored":true,"loggedBy":"Marcus Malik","loggedAt":"2026-02-20","evidenceRef":"dyehouse-audit-2026.pdf"}},{"id":"tier2","tier":2,"title":"Fabric — weaving","place":"Vila Nova de Gaia, Portugal","body":"Plain weave at a family mill. The mill reports renewable grid power; we have their word, not yet a meter audit.","claim":{"id":"tl_tier2","label":"Weaving energy source","value":"Renewable grid (brand stated)","evidence":"self_declared","register":"verified","facet":"logwood","chainAnchored":false,"loggedBy":"Marcus Malik","loggedAt":"2026-02-22"}},{"id":"tier1","tier":1,"title":"Garment — cut & sew","place":"Marvão, Portugal","body":"Final construction at Atelier Mireille. Living-wage payroll evidence has been requested but not yet filed.","claim":{"id":"tl_tier1","label":"Living-wage verification","value":"","evidence":"none","register":"verified","facet":"madder","chainAnchored":false}}],"narrative":{"by":"Mireille Tavares, founder","body":"We started Atelier Mireille because a shirt should be able to account for itself. The flax comes from a cooperative we visit each summer; the woad is grown two valleys over. Some of what we'd like to prove, we can't yet — and we'd rather show you the gap than paint over it.","audioSrc":"","transcript":"[Mireille, in Portuguese-accented English] We started Atelier Mireille because a shirt should be able to account for itself. The flax comes from a cooperative we visit each summer. The woad is grown two valleys over. Some of what we would like to prove, we cannot yet — and we would rather show you the gap than paint over it."},"care":[{"id":"c_wash","kind":"wash","label":"Wash cold, 30°C","tip":"Linen softens with every wash; skip the hot cycle to keep the weave crisp."},{"id":"c_dry","kind":"dry","label":"Line dry","tip":"Hang damp and let gravity press out most creases before they set."},{"id":"c_iron","kind":"iron","label":"Iron medium, while damp","tip":"A slightly damp linen takes a press far more easily than a dry one."},{"id":"c_bleach","kind":"bleach","label":"Do not bleach","tip":"Bleach weakens flax fibre and dulls the natural-dye tones."}],"disassembly":[{"id":"d_buttons","hardware":"Corozo buttons","location":"Front placket & cuffs","pathway":"Snip the cross-stitch from the back; buttons are plant-based and compostable."},{"id":"d_label","hardware":"Woven care label","location":"Inner left seam","pathway":"Unpick two anchor stitches; label is the only mixed-fibre component."},{"id":"d_seams","hardware":"Felled side seams","location":"Both sides","pathway":"Single cotton thread throughout — pull one end to separate panels cleanly for recycling."}],"partners":[{"id":"p_repair","label":"Find a local mender","kind":"repair","url":"https://example.org/threadtrace/repair"},{"id":"p_resale","label":"List on a resale partner","kind":"resale","url":"https://example.org/threadtrace/resale"}],"lifecycle":[{"id":"lc_1","kind":"owner","date":"2026-04-09","by":"First owner","body":"Bought in Lisbon. Wore it through a wet spring; the colour has settled rather than faded."},{"id":"lc_2","kind":"repair","date":"2026-05-30","by":"Mender, Porto","body":"Reinforced the right cuff. Single-thread seams made it a ten-minute job."},{"id":"lc_3","kind":"resale","date":"2026-06-15","by":"Resale partner","body":"Passed to a second owner. Honesty record travelled with the garment."}],"svhc":[{"id":"svhc_1","substance":"Indigo (woad-derived)","use":"Dyestuff","evidence":"certificate","evidenceRef":"dyehouse-audit-2026.pdf","loggedBy":"Marcus Malik","loggedAt":"2026-02-20"},{"id":"svhc_2","substance":"Weld extract","use":"Dyestuff","evidence":"certificate","evidenceRef":"dyehouse-audit-2026.pdf","loggedBy":"Marcus Malik","loggedAt":"2026-02-20"},{"id":"svhc_3","substance":"Softening finish","use":"Finish","evidence":"self_declared","loggedBy":"Marcus Malik","loggedAt":"2026-02-22"},{"id":"svhc_4","substance":"Flame retardant","use":"Finish","evidence":"none","loggedBy":"","loggedAt":""}]}}]
